import React, { useState, useEffect, useRef } from 'react';
import { useParams, useNavigate } from 'react-router-dom';

const AiPage = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);
  const messagesEndRef = useRef(null);
  const chatContainerRef = useRef(null);
  
  // System prompts and course data
  const courseData = {
    1: {
      title: "Password Security",
      prompt: "You are a cybersecurity expert teaching password security best practices...",
      welcome: "Hi! I'm your Password Security Assistant...",
      icon: "🔐"
    },
    // ... (other course data remains the same)
  };

  const currentCourse = courseData[id] || {
    // ... (default course remains the same)
  };

  // Initialize welcome message and scroll to top when course changes
  useEffect(() => {
    setMessages([{ role: 'assistant', content: currentCourse.welcome }]);
    
    // Scroll chat container to top when course changes
    if (chatContainerRef.current) {
      chatContainerRef.current.scrollTop = 0;
    }
  }, [id]);

  // Auto-scroll to bottom when new messages arrive
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  // ... (other functions remain the same)

  return (
    <div style={styles.container}>
      {/* Sidebar Navigation (remains the same) */}

      {/* Main Content */}
      <div style={{ 
        ...styles.content, 
        marginLeft: isSidebarCollapsed ? '60px' : '250px' 
      }}>
        {/* Header (remains the same) */}

        <div style={styles.chatContainer} ref={chatContainerRef}>
          <div style={styles.messages}>
            {/* Messages list (remains the same) */}
            <div ref={messagesEndRef} />
          </div>

          {/* Input form (remains the same) */}
        </div>
      </div>
    </div>
  );
};

// Add this to your existing styles:
const styles = {
  // ... (previous styles remain the same)
  chatContainer: {
    display: 'flex',
    flexDirection: 'column',
    height: 'calc(100vh - 180px)',
    border: '1px solid #e0e0e0',
    borderRadius: '10px',
    overflow: 'hidden',
    backgroundColor: 'white',
    boxShadow: '0 2px 10px rgba(0,0,0,0.05)',
    overflowY: 'auto'  // Ensure this is set for scrolling
  },
  // ... (rest of the styles)
};

export default AiPage;
